mapper.select:
SELECT COUNT(1)
FROM admin_users
WHERE username = #{username}

    AND id <> #{excludeId}

mapper.update:
UPDATE admin_users
SET display_name = #{displayName},
    token_version = CASE WHEN status <> #{status} THEN token_version + 1 ELSE token_version END,
    status = #{status},
    updated_at = #{updatedAt}
WHERE id = #{id}

mapper.select:
SELECT COUNT(1)
FROM admin_roles
WHERE role_code = #{roleCode}

    AND id <> #{excludeId}

mapper.update:
UPDATE admin_roles
SET role_name = #{roleName},
    description = #{description},
    status = #{status},
    updated_at = #{updatedAt}
WHERE id = #{id}

mapper.select:
SELECT 
FROM admin_permissions
WHERE 1 = 1

    AND module = #{module}


    AND status = #{status}

ORDER BY module ASC, id ASC
